package main

import (
	"context"
	"fmt"
	"log"

	"go.mongodb.org/mongo-driver/v2/bson"
	"go.mongodb.org/mongo-driver/v2/mongo"
	"go.mongodb.org/mongo-driver/v2/mongo/options"
)

func main() {
	ctx := context.Background()
	uri := "<connection-string>"
	client, err := mongo.Connect(options.Client().
		ApplyURI(uri))
	if err != nil {
		panic(err)
	}

	defer func() {
		if err := client.Disconnect(context.TODO()); err != nil {
			panic(err)
		}
	}()

	coll := client.Database("<database>").Collection("<collection>")
	const indexName = "default"
	opts := options.SearchIndexes().SetName(indexName).SetType("search")

	// Define the MongoDB Search index for the autocomplete field type
	searchIndexModel := mongo.SearchIndexModel{
		Definition: bson.D{
			{"mappings", bson.D{
				{"dynamic", true|false},
				{"fields", bson.D{
					{"<field-name>", bson.D{
						{"type", "autocomplete"},
						{"analyzer", "<lucene.analyzer>"},
						{"tokenization", "edgeGram|rightEdgeGram|nGram"},
						{"minGrams", <2>},
						{"maxGrams", <15>},
						{"foldDiacritics", true|false},
						{"similarity", bson.D{ {"type", "bm25|boolean|stableTfl"} }},
					}},
				}},
			}},
		},
		Options: opts,
	}

	// Create the index
	searchIndexName, err := coll.SearchIndexes().CreateOne(ctx, searchIndexModel)
	if err != nil {
		log.Fatalf("Failed to create the Atlas Search index: %v", err)
	}

	fmt.Println("Name of index created: " + searchIndexName)
}

dependencies {
   // MongoDB Java Sync Driver v4.11.0 or later
   implementation 'org.mongodb:mongodb-driver-sync'
}

import com.mongodb.client.MongoClient;
import com.mongodb.client.MongoClients;
import com.mongodb.client.MongoCollection;
import com.mongodb.client.MongoDatabase;
import org.bson.Document;

public class CreateIndex {
    public static void main(String[] args) {
        // connect to your Atlas cluster
        String uri = "<connection-string>";

        try (MongoClient mongoClient = MongoClients.create(uri)) {
            // set namespace
            MongoDatabase database = mongoClient.getDatabase("<database>");
            MongoCollection<Document> collection = database.getCollection("<collection>");
            String indexName = "default";

            Document searchIdx = new Document("mappings",
                    new Document("dynamic", true|false)
                        .append("fields", new Document("<field-name>", 
                                              new Document("type", "autocomplete") 
                                                  .append("analyzer", "<lucene.analyzer>")
                                                  .append("tokenization", "edgeGram|rightEdgeGram|nGram")
                                                  .append("minGrams", <2>)
                                                  .append("analymaxGramszer", <15>)
                                                  .append("foldDiacritics", true|false)
                                                  .append("similarity", new Document("type", "bm25|boolean|stableTfl"))
                                                  )));

            collection.createSearchIndex(indexName, searchIdx);
            System.out.println("New index name: " + indexName);
        } catch (Exception e) {
            System.err.println("Error creating Atlas Search index: " + e.getMessage());
        }
    }
}

