The following index definition example uses the
sample\_mflix.movies collection. The index definition indexes only the
`title` field as the `autocomplete` type to support search-as-you-type
queries against that field using the [autocomplete](autocomplete-ref)
operator. The index definition also specifies the following:

- Use the [standard analyzer](ref-standard-analyzer) analyzer to divide
  text values into terms based on word boundaries.

- Use the `edgeGram` tokenization strategy to index characters
  starting at the left side of the words .

- Index a minimum of `3` characters per indexed sequence.

- Index a maximum of `5` characters per indexed sequence.

- Include diacritic marks in the index and query text.

- Use the `stableTfl` [Score Details](fts-similarity-algorithms) to ensure consistent document scoring
  across all search nodes and replica set members.

```go
package main

import (
	"context"
	"fmt"
	"log"

	"go.mongodb.org/mongo-driver/v2/bson"
	"go.mongodb.org/mongo-driver/v2/mongo"
	"go.mongodb.org/mongo-driver/v2/mongo/options"
)

func main() {
	ctx := context.Background()
	uri := "<connection-string>"
	client, err := mongo.Connect(options.Client().
		ApplyURI(uri))
	if err != nil {
		panic(err)
	}

	defer func() {
		if err := client.Disconnect(context.TODO()); err != nil {
			panic(err)
		}
	}()

	coll := client.Database("sample_mflix").Collection("movies")
	const indexName = "default"
	opts := options.SearchIndexes().SetName(indexName).SetType("search")

	// Define the MongoDB Search index for the autocomplete field type
	searchIndexModel := mongo.SearchIndexModel{
		Definition: bson.D{
			{"mappings", bson.D{
				{"dynamic", false},
				{"fields", bson.D{
					{"title", bson.D{
						{"type", "autocomplete"},
						{"analyzer", "lucene.standard"},
						{"tokenization", "edgeGram"},
						{"minGrams", 3},
						{"maxGrams", 5},
						{"foldDiacritics", false},
						{"similarity", bson.D{{"type", "stableTfl"}}},
					}},
				}},
			}},
		},
		Options: opts,
	}

	// Create the index
	searchIndexName, err := coll.SearchIndexes().CreateOne(ctx, searchIndexModel)
	if err != nil {
		log.Fatalf("Failed to create the Atlas Search index: %v", err)
	}

	fmt.Println("Name of index created: " + searchIndexName)
}

```

