The following index definition example uses the
sample\_mflix.movies collection. The index definition indexes only the
`title` field as the `autocomplete` type to support search-as-you-type
queries against that field using the [autocomplete](autocomplete-ref)
operator. The index definition also specifies the following:

- Use the [standard analyzer](ref-standard-analyzer) analyzer to divide
  text values into terms based on word boundaries.

- Use the `edgeGram` tokenization strategy to index characters
  starting at the left side of the words .

- Index a minimum of `3` characters per indexed sequence.

- Index a maximum of `5` characters per indexed sequence.

- Include diacritic marks in the index and query text.

- Use the `stableTfl` [Score Details](fts-similarity-algorithms) to ensure consistent document scoring
  across all search nodes and replica set members.

```java
import com.mongodb.client.MongoClient;
import com.mongodb.client.MongoClients;
import com.mongodb.client.MongoCollection;
import com.mongodb.client.MongoDatabase;
import org.bson.Document;

public class CreateIndex {
    public static void main(String[] args) {
        // connect to your Atlas cluster
        String uri = "<connection-string>";

        try (MongoClient mongoClient = MongoClients.create(uri)) {
            // set namespace
            MongoDatabase database = mongoClient.getDatabase("sample_mflix");
            MongoCollection<Document> collection = database.getCollection("movies");
            String indexName = "default";

            Document searchIdx = new Document("mappings",
                    new Document("dynamic", false)
                        .append("fields", new Document("title", 
                                              new Document("type", "autocomplete")
                                                  .append("analyzer", "lucene.standard")
                                                  .append("tokenization", "edgeGram")
                                                  .append("minGrams", 3)
                                                  .append("maxGrams", 5)
                                                  .append("foldDiacritics", false)
                                                  .append("similarity", new Document("type", "stableTfl"))
                                                  )));

            collection.createSearchIndex(indexName, searchIdx);
            System.out.println("New index name: " + indexName);
        } catch (Exception e) {
            System.err.println("Error creating Atlas Search index: " + e.getMessage());
        }
    }
}
```

